#include<bits/stdc++.h>
#define int long long
using namespace std;
int a[25];
vector <int> v[25];
vector <int> ans;
int maxi;
void dfs(int x, vector<int>vv, int cnt){
	if(maxi < cnt){
		ans = vv;
		maxi = cnt;
	}
	for(int i = 0; i < v[x].size(); i++){
		vv.push_back(v[x][i]);
		dfs(v[x][i], vv, cnt + a[v[x][i]]);
		vv.pop_back();
	}
}
signed main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)cin >> a[i];
	for(int i = 1; i <= n - 1; i++){
		for(int j = i + 1; j <= n; j++){
			int x;
			cin >> x;
			if(x == 1)v[i].push_back(j);
		}
	}
	for(int i = 1; i <= n; i++){
		vector <int> vv;
		vv.push_back(i);
		dfs(i, vv, a[i]);
	}
//	cout << 7;
	for(int i = 0; i < ans.size(); i++)cout << ans[i] << " ";
	cout << endl;
	cout << maxi;
}
